CREATE TABLE `inbound_emails` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `property_id` int DEFAULT NULL,
  `created_reservation_id` int DEFAULT NULL,
  `provider` varchar(50) NOT NULL DEFAULT 'resend',
  `event_type` varchar(100) NOT NULL DEFAULT 'email.received',
  `email_id` varchar(255) DEFAULT NULL,
  `to_email` varchar(255) NOT NULL,
  `from_email` varchar(255) DEFAULT NULL,
  `subject` varchar(255) DEFAULT NULL,
  `body_text` longtext,
  `body_html` longtext,
  `attachments_json` json DEFAULT NULL,
  `headers_json` json DEFAULT NULL,
  `raw_payload` json DEFAULT NULL,
  `parsing_status` enum('pending','processed','ignored','error') NOT NULL DEFAULT 'pending',
  `parsing_notes` text,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_inbound_user` (`user_id`),
  KEY `idx_inbound_property` (`property_id`),
  KEY `idx_inbound_email_id` (`email_id`),
  KEY `idx_inbound_status` (`parsing_status`),
  KEY `fk_inbound_reservation` (`created_reservation_id`),
  CONSTRAINT `fk_inbound_property` FOREIGN KEY (`property_id`) REFERENCES `properties` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_inbound_reservation` FOREIGN KEY (`created_reservation_id`) REFERENCES `reservations` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_inbound_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
